        @mcp.tool()
        async def html_extract_links(
            input_filename: str,
        ) -> dict:
            """
            Extract all hyperlinks from an HTML document stored on the server.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.html') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the HTML file to process, e.g. 'report.html' — must already exist in ASPOSE_FILES_PATH.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "links": list[dict] (each dict contains "url" and "text"),
                    "count": int
                }
        
            Raises:
                FileNotFoundError: If the specified HTML file does not exist in ASPOSE_FILES_PATH.
                Exception: Any unexpected error raised by Aspose.HTML.
        
            Example:
                >>> result = await html_extract_links("example.html")
                >>> result["links"]
                [{'url': 'https://example.com', 'text': 'Example'}]
            """
            # ----------------------------------------------------------------------
            # Resolve and validate the input filename (must be a bare name)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # Sanitize the provided filename
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
        
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Load Aspose.HTML and extract links
            # ----------------------------------------------------------------------
            try:
                import aspose.html as ah  # lazy import as required by policy
                apply_license_for("aspose.html")
        
                links = []
                with ah.HTMLDocument(resolved_input) as doc:
                    a_tags = doc.get_elements_by_tag_name('a')
                    for el in a_tags:
                        href = el.get_attribute('href') or ''
                        text = el.text_content or ''
                        links.append({'url': href, 'text': text.strip()})
        
                result = {
                    "status": "success",
                    "message": "Links extracted successfully.",
                    "links": links,
                    "count": len(links),
                }
                logger.debug("Extracted %d links from %s", len(links), input_filename)
                return result
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to extract links from %s", input_filename)
                return {
                    "status": "error",
                    "message": str(exc),
                }

        @mcp.tool()
        async def html_query_elements(
            input_filename: str,
            css_selector: str,
        ) -> dict:
            """
            Query HTML document for elements matching a CSS selector.
        
            IMPORTANT:
                All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
                The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
                Do NOT ask the user to upload a file — files are pre-placed in the server folder by the user.
                The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the HTML file to process, e.g. "index.html".
                css_selector: CSS selector string (e.g. "h1", ".class", "#id").
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "selector": str,
                    "count": int,
                    "elements": list[dict]  # each dict contains "tag" and "text"
                }
        
            Raises:
                FileNotFoundError: If the specified HTML file does not exist in ASPOSE_FILES_PATH.
                Exception: Any unexpected error from Aspose.HTML processing.
        
            Example:
                >>> result = await html_query_elements("sample.html", "p.intro")
                >>> result["elements"]
                [{'tag': 'p', 'text': 'Welcome to the site.'}, ...]
            """
            # ------------------------------------------------------------------
            # Validate and resolve the input file (must be a bare filename)
            # ------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ------------------------------------------------------------------
            # Import Aspose.HTML after validation
            # ------------------------------------------------------------------
            import logging
            import aspose.html as ah
            apply_license_for("aspose.html")
        
            logger = logging.getLogger(__name__)
        
            try:
                with ah.HTMLDocument(resolved_input) as doc:
                    nodes = doc.query_selector_all(css_selector)
        
                    elements = []
                    for node in nodes:
                        tag = node.node_name.lower() if node.node_name else ''
                        text = node.text_content or ''
                        elements.append({'tag': tag, 'text': text.strip()})
        
                result = {
                    "status": "success",
                    "message": f"Found {len(elements)} element(s) for selector '{css_selector}'.",
                    "selector": css_selector,
                    "count": len(elements),
                    "elements": elements,
                }
                logger.debug("HTML query completed: %s", result)
                return result
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Error querying HTML document")
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def html_add_element(
            input_filename: str,
            tag: str,
            content: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Add a new HTML element to an existing HTML document.
        
            IMPORTANT:
            - All *_filename parameters accept ONLY the bare filename (e.g. 'scan.html') — no path, no directory, no drive letter, no slash.
            - The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            - Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            - The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the source HTML file, e.g. "index.html".
                tag: HTML tag name to create, e.g. "p", "div", "span".
                content: Inner HTML content for the new element.
                output_filename: Optional bare filename for the resulting HTML file. If None, a temporary
                                 filename is generated.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: If the input HTML file does not exist.
                Exception: Propagates any unexpected error from Aspose.
        
            Example:
                result = await html_add_element(
                    input_filename="report.html",
                    tag="p",
                    content="Added paragraph.",
                    output_filename="report_updated.html"
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output location
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # generate a temporary filename with .html extension
                temp_path = temp_output_path("aspose_html_result", ".html")
                resolved_output = str(temp_path)  # Aspose expects a plain string
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Aspose.HTML processing
            # ----------------------------------------------------------------------
            try:
                import aspose.html as ah
                apply_license_for("aspose.html")
        
                with ah.HTMLDocument(resolved_input) as doc:
                    new_el = doc.create_element(tag)
                    new_el.inner_html = content
                    if doc.body is not None:
                        doc.body.append_child(new_el)
                    doc.save(resolved_output)
        
                return {
                    "status": "success",
                    "message": f"Element <{tag}> added and saved to {output_filename}.",
                    "output_filename": output_filename,
                    "output_path": resolved_output,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Aspose.HTML processing failed")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }
